package com.example.entitylifecycle.dto;

import com.example.entitylifecycle.entity.Product;

import java.math.BigDecimal;
import java.time.Instant;

/**
 * Outbound DTO (Data Transfer Object) returned by the REST API for every
 * product-related response.
 *
 * <p>This record surfaces the fields that demonstrate JPA lifecycle event
 * behaviour to the API consumer:
 * <ul>
 *   <li>{@code slug}            — auto-generated by {@code @PrePersist}; never
 *       supplied by the client.</li>
 *   <li>{@code discountedPrice} — computed by {@code @PostLoad} on every DB
 *       load; never stored in the database.</li>
 *   <li>{@code createdAt}       — stamped by {@code @PrePersist}; immutable.</li>
 *   <li>{@code updatedAt}       — stamped by {@code @PrePersist} and refreshed
 *       by the service on every update.</li>
 * </ul>
 *
 * <p>The static factory method {@link #from(Product)} keeps the mapping logic
 * co-located with the DTO class and avoids a separate mapper utility.
 *
 * @param id              database-generated primary key
 * @param name            product display name
 * @param slug            URL-friendly slug — auto-generated by {@code @PrePersist}
 * @param description     full product description
 * @param price           base price before discount
 * @param discountPercent discount percentage (0–100)
 * @param discountedPrice computed price after applying the discount — set by {@code @PostLoad}
 * @param createdAt       UTC instant when the entity was first persisted — set by {@code @PrePersist}
 * @param updatedAt       UTC instant of the most recent update
 */
public record ProductResponse(
        Long id,
        String name,
        String slug,
        String description,
        BigDecimal price,
        int discountPercent,
        BigDecimal discountedPrice,
        Instant createdAt,
        Instant updatedAt
) {

    /**
     * Creates a {@code ProductResponse} from a persisted {@link Product} entity.
     *
     * <p>By the time this factory method is called, all lifecycle callbacks will
     * already have run:
     * <ul>
     *   <li>{@code @PrePersist}  has set {@code slug}, {@code createdAt}, and
     *       {@code updatedAt}.</li>
     *   <li>{@code @PostLoad}    has set {@code discountedPrice} (on entities
     *       loaded from the DB).</li>
     *   <li>{@code @PrePersist} also calls {@code computeDiscountedPrice()} so
     *       {@code discountedPrice} is available immediately after the first save
     *       before any subsequent load.</li>
     * </ul>
     *
     * @param product the JPA entity to convert
     * @return a fully populated response DTO
     */
    public static ProductResponse from(Product product) {
        return new ProductResponse(
                product.getId(),
                product.getName(),
                product.getSlug(),
                product.getDescription(),
                product.getPrice(),
                product.getDiscountPercent(),
                product.getDiscountedPrice(),
                product.getCreatedAt(),
                product.getUpdatedAt()
        );
    }
}
